SELECT [Lista Clienti GDPR Privacy-step1].CustomerCheckCode, [Lista Clienti GDPR Privacy-step1].CustomerName, [Lista Clienti GDPR Privacy-step1].[Business E-Mail_] AS [Business E-Mail], [Lista Clienti GDPR Privacy-step1].Geo1Desc, [Lista Clienti GDPR Privacy-step1].Geo2Desc, Max([Lista Clienti GDPR Privacy-step1].[Data Ordine]) AS [Data Ordine], Max([Lista Clienti GDPR Privacy-step1].AP) AS AP, Max([Lista Clienti GDPR Privacy-step1].[AP GIRL]) AS [AP GIRL], Max([Lista Clienti GDPR Privacy-step1].BEPOSITIVE) AS BEPOSITIVE, Max([Lista Clienti GDPR Privacy-step1].BLAC) AS BLAC, Max([Lista Clienti GDPR Privacy-step1].BLK) AS BLK, Max([Lista Clienti GDPR Privacy-step1].BLAUER) AS BLAUER, Max([Lista Clienti GDPR Privacy-step1].GANT) AS GANT, Max([Lista Clienti GDPR Privacy-step1].NAPA) AS NAPA
FROM [Lista Clienti GDPR Privacy-step1]
GROUP BY [Lista Clienti GDPR Privacy-step1].CustomerCheckCode, [Lista Clienti GDPR Privacy-step1].CustomerName, [Lista Clienti GDPR Privacy-step1].[Business E-Mail_], [Lista Clienti GDPR Privacy-step1].Geo1Desc, [Lista Clienti GDPR Privacy-step1].Geo2Desc;

